/**
 * main.ts — bootstrap. Wires the mock RGS to the client and renders.
 *
 * ZERO browser storage: all state lives in memory (the MockRgs instance). The
 * info modal's numbers are pulled straight from /game-math so the disclosure can
 * never drift from the certified code.
 */

import { CurveView } from "./src/client/CurveView";
import { Juice } from "./src/client/Juice";
import { Hud } from "./src/client/Hud";
import { Feed } from "./src/client/Feed";
import { MoonPool } from "./src/client/MoonPool";
import { SharedGame } from "./src/client/SharedGame";
import { RgsClient } from "./src/net/RgsClient";
import { EDGE, RTP, MOONPOOL_CONTRIB, MOONPOOL_ODDS } from "./src/game-math";

/**
 * Where the RGS lives. Override with ?rgs=wss://host/ws.
 * Hosted build (VITE_RGS_PATH=/ws) → same-origin path on the unified server.
 * Dev → :8080 (standalone RGS).
 */
function resolveRgsUrl(): string {
  const q = new URLSearchParams(location.search).get("rgs");
  if (q) return q;
  const proto = location.protocol === "https:" ? "wss:" : "ws:";
  const path = import.meta.env.VITE_RGS_PATH as string | undefined;
  if (path) return `${proto}//${location.host}${path}`;
  return `${proto}//${location.hostname || "localhost"}:8080/ws`;
}

const $ = (id: string) => document.getElementById(id) as HTMLElement;

async function main(): Promise<void> {
  const stage = $("stage");
  const juice = new Juice({ bigwin: $("bigwin"), mult: $("mult"), stage });
  const curve = new CurveView();
  await curve.init(stage);

  const hud = new Hud();
  const moonPool = new MoonPool({ el: $("pool"), msgEl: $("msg"), curve, juice });

  // Forward-declared so the cosmetic feed can read the live multiplier.
  let game: SharedGame;
  const feed = new Feed($("feed"), () => (game ? game.liveMult() : 1));

  // Which title to play. Override with ?game=comet|pulse; defaults to ascent.
  const gameId = new URLSearchParams(location.search).get("game") || "ascent";
  const rgs = new RgsClient(resolveRgsUrl(), "player-demo", "demo", gameId);
  game = new SharedGame(rgs, hud, curve, juice, feed, moonPool, stage, $("hash"));
  try {
    await game.boot();
  } catch (err) {
    hud.setTicker("can't reach the game server");
    hud.setMsg("the RGS is offline — start ascent-rgs (npm start) and reload");
    console.error("RGS connect failed:", err);
  }

  // sound toggle
  const soundEl = $("sound");
  soundEl.addEventListener("click", () => {
    soundEl.textContent = juice.toggleSound() ? "🔊" : "🔇";
  });

  wireInfoModal();
  fillCopy();
}

function wireInfoModal(): void {
  const modal = $("modal");
  $("info-btn").addEventListener("click", () => modal.classList.add("open"));
  $("modal-close").addEventListener("click", () => modal.classList.remove("open"));
  modal.addEventListener("click", (e) => {
    if (e.target === modal) modal.classList.remove("open");
  });
}

function fillCopy(): void {
  const rtpPct = (RTP * 100).toFixed(0);
  const edgePct = (EDGE * 100).toFixed(0);
  const contribPct = (MOONPOOL_CONTRIB * 100).toFixed(1);

  $("footer").innerHTML =
    `Play credits only — prototype. Base game ${rtpPct}% RTP (${edgePct}% edge), shown openly. ` +
    `Rug point precommitted (hash before, seed after).<br>` +
    `Moon Pool grows ${contribPct}% of each buy-in &amp; drops on a rare provably-fair trigger ` +
    `(~1 in ${MOONPOOL_ODDS} rounds) to anyone holding a bet — win or lose.`;

  $("modal-body").innerHTML = `
    <h3>The base game</h3>
    <p>You buy into a token launch. The price (multiplier) pumps from 1.00×. Sell
    before the dev rugs and you keep <b>buy × multiplier</b>. Get caught holding
    and you lose your buy. Return-to-player is <b>${rtpPct}%</b> (house edge
    ${edgePct}%), applied as one transparent edge — there is no adaptive
    difficulty and no memory of your past rounds.</p>

    <h3>Provably fair</h3>
    <p>Before each round the server publishes <code>SHA-256(serverSeed)</code> — a
    commitment it cannot change. After the round it reveals the
    <code>serverSeed</code>. The crash point and the Moon Pool roll are derived by
    HMAC-SHA256 from <b>serverSeed + your clientSeed + nonce</b>, using two
    independent tags so neither can be predicted from the other. Re-hash the
    revealed seed to confirm it matches the commitment, then recompute both
    outcomes yourself.</p>

    <h3>🌙 Moon Pool</h3>
    <p>A progressive jackpot that sits <b>on top of</b> the ${rtpPct}% base game —
    it does not change base RTP. <b>${contribPct}%</b> of every buy-in feeds the
    pool. Each round has an independent ~1-in-${MOONPOOL_ODDS} provably-fair
    trigger; on a hit the whole pool is paid to anyone holding a bet that round —
    <b>win or loss</b> — then it resets to its seed value. In production the pool
    is shared across all players and lives on the server.</p>

    <h3>Responsible by default</h3>
    <p>No near-miss fakery, no loss dressed up as a win, no loss-chasing nudges,
    no auto-rebet. Your balance and the ${edgePct}% edge are always on screen.
    These are play credits with no cash value.</p>
  `;
}

void main();
