/**
 * Feed.ts — cosmetic live cash-out ticker. Purely decorative flavor; these are
 * not real players and nothing here affects outcomes or the wallet.
 */

import { rollUsername } from "./flavor";

export class Feed {
  private el: HTMLElement;
  private timer: ReturnType<typeof setInterval> | null = null;
  private getMult: () => number;

  constructor(el: HTMLElement, getMult: () => number) {
    this.el = el;
    this.getMult = getMult;
  }

  start(): void {
    this.el.innerHTML = "";
    this.stop();
    this.timer = setInterval(() => {
      const mult = this.getMult();
      const at = (1 + Math.random() * Math.min(mult * 1.5, 8)).toFixed(2);
      const row = document.createElement("div");
      row.className = "f";
      row.innerHTML = `<span>${rollUsername()}</span><span class="m">${at}×</span>`;
      this.el.prepend(row);
      while (this.el.children.length > 5) this.el.lastChild?.remove();
    }, 700 + Math.random() * 500);
  }

  stop(): void {
    if (this.timer) clearInterval(this.timer);
    this.timer = null;
  }
}
