/**
 * flavor.ts — cosmetic memecoin flavor: ticker symbols + degen usernames.
 * Pure presentation. Nothing here touches outcomes.
 */

const COIN_A = ["PEPE", "DOGE", "MOON", "WOJAK", "CHAD", "FLOKI", "BONK", "TURBO", "GIGA", "MOG", "POPCAT", "BASED", "NEIRO", "WIF"];
const COIN_B = ["INU", "2.0", "COIN", "MAXI", "69", "AI", "SOL", "X", ""];
const USERNAMES = ["degen_mike", "0xWhale", "aping_in", "jeetkiller", "satoshi_jr", "gm_ser", "liqd_again", "moonboy", "paperhandz", "rugproof", "exit_liquidity", "ngmi_andy", "wagmi_wendy", "floorsweeper"];

const pick = <T>(arr: T[]): T => arr[(Math.random() * arr.length) | 0];

export function rollTicker(): string {
  return "$" + pick(COIN_A) + pick(COIN_B);
}

export function rollUsername(): string {
  return pick(USERNAMES);
}

/** Phrases for the launch ticker line. */
export function launchLine(ticker: string): string {
  const tails = ["holders piling in", "trending on the timeline", "liquidity locked (allegedly)", "influencers shilling", "volume spiking"];
  return `${ticker} launched · ${pick(tails)}`;
}
