/**
 * RgsClient.ts — thin WebSocket client to the Ascent RGS.
 *
 * Owns the socket and the typed message plumbing ONLY. It computes nothing about
 * outcomes: it sends intents (place_bet, cash_out) and emits server messages for
 * the game loop to render. This replaces the offline MockRgs as the seam to the
 * (now server-authoritative) RGS.
 */

import type { ClientMessage, ServerMessage, ServerType } from "./protocol";

type Handler<T extends ServerType> = (msg: Extract<ServerMessage, { type: T }>) => void;

/** Cryptographically-random hex string — the player's per-bet fairness contribution. */
function randomHex(bytes: number): string {
  const b = new Uint8Array(bytes);
  crypto.getRandomValues(b);
  return Array.from(b, (x) => x.toString(16).padStart(2, "0")).join("");
}

export class RgsClient {
  private ws: WebSocket | null = null;
  private handlers = new Map<ServerType, Set<(m: ServerMessage) => void>>();
  private anyHandlers = new Set<(m: ServerMessage) => void>();

  constructor(
    private url: string,
    private sessionToken = "player-demo",
    private mode: "real" | "demo" = "demo",
    private gameId = "ascent",
  ) {}

  /** Resolves on the first `welcome` message. */
  connect(): Promise<Extract<ServerMessage, { type: "welcome" }>> {
    return new Promise((resolve, reject) => {
      const ws = new WebSocket(this.url);
      this.ws = ws;
      const timer = window.setTimeout(() => reject(new Error("rgs_connect_timeout")), 8000);

      ws.addEventListener("open", () => {
        this.send({ type: "hello", sessionToken: this.sessionToken, mode: this.mode, gameId: this.gameId });
      });
      ws.addEventListener("message", (ev) => {
        let msg: ServerMessage;
        try {
          msg = JSON.parse(ev.data as string) as ServerMessage;
        } catch {
          return;
        }
        if (msg.type === "welcome") {
          window.clearTimeout(timer);
          resolve(msg);
        }
        this.dispatch(msg);
      });
      ws.addEventListener("error", () => reject(new Error("rgs_socket_error")));
      ws.addEventListener("close", () => this.dispatch({ type: "error", code: "closed", message: "connection closed" }));
    });
  }

  on<T extends ServerType>(type: T, fn: Handler<T>): void {
    let set = this.handlers.get(type);
    if (!set) this.handlers.set(type, (set = new Set()));
    set.add(fn as (m: ServerMessage) => void);
  }

  onAny(fn: (m: ServerMessage) => void): void {
    this.anyHandlers.add(fn);
  }

  placeBet(stakeMinor: number, autoCashOut?: number): void {
    // Contribute fresh, unpredictable entropy with every bet. The server mixes all
    // of a round's contributions into that round's client seed at betting close,
    // so the operator could not have known the outcome when it built its seed
    // chain (anti-genesis-grind). This is the player's half of provable fairness.
    this.send({ type: "place_bet", stake: stakeMinor, autoCashOut, clientEntropy: randomHex(16) });
  }

  cashOut(betId: string): void {
    this.send({ type: "cash_out", betId });
  }

  private send(msg: ClientMessage): void {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) this.ws.send(JSON.stringify(msg));
  }

  private dispatch(msg: ServerMessage): void {
    this.handlers.get(msg.type)?.forEach((fn) => fn(msg));
    this.anyHandlers.forEach((fn) => fn(msg));
  }
}
