/**
 * protocol.ts — client-side mirror of the RGS WebSocket contract.
 *
 * Kept in sync with ascent-rgs/src/protocol/messages.ts. Money crosses the wire
 * as integer MINOR units; the client divides by MINOR_PER_CREDIT for display.
 * The client only ever SENDS intents and RENDERS server truth.
 */

export const MINOR_PER_CREDIT = 100;
export const toCredits = (m: number): number => m / MINOR_PER_CREDIT;
export const toMinor = (c: number): number => Math.round(c * MINOR_PER_CREDIT);

export type ClientMessage =
  | { type: "hello"; sessionToken: string; mode: "real" | "demo"; gameId?: string }
  | { type: "place_bet"; stake: number; autoCashOut?: number; clientEntropy?: string }
  | { type: "cash_out"; betId: string }
  | { type: "ping" };

export interface PublicRound {
  roundId: string;
  roundNumber: number;
  commitment: string; // SHA-256(serverSeed), published before the round
  nonce: number;
  bettingEndsAt: number;
  // client seed arrives at betting_closed (after player entropy is mixed in)
}

export interface RevealedRound {
  roundId: string;
  roundNumber: number;
  crashPoint: number;
  serverSeed: string;
  clientSeed: string;
  nonce: number;
  jackpotTriggered: boolean;
}

export type ServerMessage =
  | { type: "welcome"; sessionId: string; currency: string; balance: number; edge: number; moonPool: number }
  | { type: "round_open"; round: PublicRound; moonPool: number }
  | { type: "betting_closed"; roundId: string; clientSeed: string; externalEntropy?: string; externalSource?: string }
  | { type: "tick"; roundId: string; multiplier: number }
  | { type: "bet_accepted"; betId: string; stake: number; balance: number }
  | { type: "cash_out"; betId: string; multiplier: number; payout: number; balance: number }
  | { type: "cash_out_failed"; betId: string; reason: string }
  | { type: "jackpot"; betId: string; award: number; balance: number }
  | { type: "crash"; round: RevealedRound; moonPool: number }
  | { type: "balance"; balance: number }
  | { type: "pong" }
  | { type: "error"; code: string; message: string };

export type ServerType = ServerMessage["type"];
