/**
 * crash.ts — the crash-point formula. PURE. Single source of truth for EDGE.
 *
 * The client NEVER calls this to decide an outcome; the RGS does. The client
 * and the test suite import it only to render and to verify.
 */

import { floatFor, TAG_CRASH, type RoundSeeds } from "./provablyfair";

/**
 * House edge. 0.03 => 97% RTP. This is the ONE place the number lives; the
 * docs, the info panel, and the tests all trace back here.
 */
export const EDGE = 0.03;

/** Theoretical RTP implied by the edge. */
export const RTP = 1 - EDGE;

/** Lowest possible multiplier — an "instant rug". */
export const MIN_MULTIPLIER = 1.0;

/**
 * Map a uniform r in [0, 1) to a crash multiplier.
 *
 *   crash = floor( (1 - EDGE) / (1 - r) * 100 ) / 100
 *
 * Anything below 1.00 clamps to an instant rug at 1.00x. Truncating to 2 dp is
 * what creates the ~EDGE share of instant rugs and yields P(crash >= x) ~= RTP/x.
 * Pure function of r — no state, no history, no adaptive difficulty.
 */
export function crashFromFloat(r: number): number {
  if (r < 0 || r >= 1 || Number.isNaN(r)) {
    throw new RangeError(`crashFromFloat expects r in [0,1); got ${r}`);
  }
  const raw = Math.floor((RTP / (1 - r)) * 100) / 100;
  return raw < MIN_MULTIPLIER ? MIN_MULTIPLIER : raw;
}

/** Convenience: did this float produce an instant rug? */
export function isInstantRug(r: number): boolean {
  return crashFromFloat(r) === MIN_MULTIPLIER;
}

/** Derive the crash point for a round from its committed seeds. */
export function crashPoint(seeds: RoundSeeds): number {
  return crashFromFloat(floatFor(seeds, TAG_CRASH));
}
