/**
 * Theme.ts — design tokens, carried over from the approved prototype.
 * Colors as both CSS strings and 0xRRGGBB numbers (for PixiJS).
 */

export const COLORS = {
  pink: "#FF2E97",
  cyan: "#22D3EE",
  green: "#2BFF88",
  gold: "#FFD23F",
  orange: "#FF9F1C",
  rug: "#FF3653",
  bg: "#160833",
  text: "#ffffff",
  muted: "#B9A9E0",
} as const;

export type RGB = [number, number, number];

/** 0xRRGGBB for Pixi. */
export function rgbToHex([r, g, b]: RGB): number {
  return ((r & 0xff) << 16) | ((g & 0xff) << 8) | (b & 0xff);
}

export function rgbToCss([r, g, b]: RGB, a = 1): string {
  return a >= 1 ? `rgb(${r},${g},${b})` : `rgba(${r},${g},${b},${a})`;
}

export const RUG_RGB: RGB = [255, 54, 83];

/**
 * The multiplier color journey:
 * cyan(<1.5) → green(<2.5) → gold(<5) → orange(<12) → pink(12+).
 */
export function multColor(m: number): RGB {
  if (m < 1.5) return [34, 211, 238]; // cyan
  if (m < 2.5) return [43, 255, 136]; // green
  if (m < 5) return [255, 210, 63]; // gold
  if (m < 12) return [255, 159, 28]; // orange
  return [255, 46, 151]; // pink
}

function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

/**
 * Sky gradient that shifts cool→hot as the multiplier climbs. Bright, saturated
 * casino energy: deep electric violet at launch, blazing magenta/orange as it
 * pumps. `rugged` slams it to a hot red crash sky. Pixi renders transparently
 * on top so the neon curve composites over this.
 */
export function skyGradient(mult: number, rugged = false): string {
  if (rugged) {
    // crash sky — hot red, unmistakable
    return "radial-gradient(120% 90% at 50% 8%, #FF5A6E 0%, #C01533 45%, #3A0518 100%)";
  }
  const t = Math.min(1, (mult - 1) / 12);
  // top of sky: electric violet → blazing magenta
  const top: RGB = [
    Math.round(lerp(58, 255, t)),
    Math.round(lerp(20, 70, t)),
    Math.round(lerp(120, 170, t)),
  ];
  // bottom of sky: deep indigo → hot orange-pink glow
  const bot: RGB = [
    Math.round(lerp(30, 255, t)),
    Math.round(lerp(12, 120, t)),
    Math.round(lerp(95, 60, t)),
  ];
  return `radial-gradient(130% 100% at 50% 100%, ${rgbToCss(bot)} 0%, ${rgbToCss(top)} 100%)`;
}

