/**
 * Juice.ts — procedural WebAudio + screen-level visual flourishes.
 *
 * All sound is synthesized (no asset files). Visual particle bursts live in
 * CurveView (Pixi); this handles the running hum, one-shot sounds, the big-win
 * text, the multiplier pop, and the screen shake.
 *
 * RESPONSIBLE BY DEFAULT: effects celebrate real wins only. There is no
 * loss-disguised-as-win sound and no near-miss audio cue on a rug.
 */

export class Juice {
  private actx: AudioContext | null = null;
  private toneOsc: OscillatorNode | null = null;
  private toneGain: GainNode | null = null;
  soundOn = true;

  private bigwinEl: HTMLElement;
  private multEl: HTMLElement;
  private stageEl: HTMLElement;

  constructor(opts: { bigwin: HTMLElement; mult: HTMLElement; stage: HTMLElement }) {
    this.bigwinEl = opts.bigwin;
    this.multEl = opts.mult;
    this.stageEl = opts.stage;
  }

  /** Must be called from a user gesture to satisfy autoplay policies. */
  ensureAudio(): void {
    if (!this.actx) {
      const Ctor = window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext;
      this.actx = new Ctor();
    }
    if (this.actx.state === "suspended") void this.actx.resume();
  }

  toggleSound(): boolean {
    this.soundOn = !this.soundOn;
    if (!this.soundOn) this.stopTone();
    return this.soundOn;
  }

  // ---- running hum that rises with the multiplier ----
  startTone(): void {
    if (!this.soundOn || !this.actx) return;
    this.stopTone();
    const osc = this.actx.createOscillator();
    const gain = this.actx.createGain();
    osc.type = "sine";
    osc.frequency.value = 220;
    gain.gain.value = 0.04;
    osc.connect(gain).connect(this.actx.destination);
    osc.start();
    this.toneOsc = osc;
    this.toneGain = gain;
  }

  setTone(m: number): void {
    if (this.toneOsc && this.actx) {
      this.toneOsc.frequency.setTargetAtTime(180 + m * 60, this.actx.currentTime, 0.05);
    }
  }

  stopTone(): void {
    if (this.toneOsc && this.toneGain && this.actx) {
      this.toneGain.gain.setTargetAtTime(0, this.actx.currentTime, 0.05);
      this.toneOsc.stop(this.actx.currentTime + 0.2);
    }
    this.toneOsc = null;
    this.toneGain = null;
  }

  // ---- one-shot sounds ----
  private blip(freqs: number[], dur = 0.12, type: OscillatorType = "triangle"): void {
    if (!this.soundOn || !this.actx) return;
    const ctx = this.actx;
    freqs.forEach((f, i) => {
      const o = ctx.createOscillator();
      const g = ctx.createGain();
      o.type = type;
      o.frequency.value = f;
      const t0 = ctx.currentTime + i * 0.05;
      g.gain.setValueAtTime(0.0001, t0);
      g.gain.exponentialRampToValueAtTime(0.12, t0 + 0.01);
      g.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);
      o.connect(g).connect(ctx.destination);
      o.start(t0);
      o.stop(t0 + dur);
    });
  }

  winSound(): void {
    this.blip([523, 659, 784, 1047], 0.15);
  }

  moonSound(): void {
    this.blip([392, 523, 659, 784, 1047, 1319], 0.18, "sine");
  }

  rugSound(): void {
    if (!this.soundOn || !this.actx) return;
    const ctx = this.actx;
    const o = ctx.createOscillator();
    const g = ctx.createGain();
    o.type = "sawtooth";
    o.frequency.setValueAtTime(160, ctx.currentTime);
    o.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + 0.4);
    g.gain.setValueAtTime(0.18, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + 0.5);
    o.connect(g).connect(ctx.destination);
    o.start();
    o.stop(ctx.currentTime + 0.5);
  }

  // ---- visual flourishes ----
  popMult(): void {
    this.multEl.classList.add("pop");
    setTimeout(() => this.multEl.classList.remove("pop"), 120);
  }

  bigWin(text: string, cls: "gold" | "moon"): void {
    const e = this.bigwinEl;
    e.className = "bigwin " + cls;
    e.textContent = text;
    void e.offsetWidth; // reflow to restart the animation
    e.classList.add("show");
  }

  shake(): void {
    const s = this.stageEl;
    s.classList.remove("shake");
    void s.offsetWidth;
    s.classList.add("shake");
  }
}
