/**
 * Hud.ts — the DOM controls: balance, bet + auto-sell inputs, the action button,
 * the overlay text (ticker / multiplier / message), and the history chips.
 *
 * RESPONSIBLE BY DEFAULT: balance and the 97% edge are always visible; there is
 * no auto-rebet, no loss-chasing nudge, and no hidden state.
 */

import { multColor, rgbToCss } from "./Theme";
import { fmt } from "./format";

export type ActionMode = "buy" | "sell" | "wait";

export class Hud {
  private bal = document.getElementById("bal") as HTMLElement;
  private betInput = document.getElementById("bet") as HTMLInputElement;
  private autoInput = document.getElementById("auto") as HTMLInputElement;
  private action = document.getElementById("action") as HTMLButtonElement;
  private ticker = document.getElementById("ticker") as HTMLElement;
  private mult = document.getElementById("mult") as HTMLElement;
  private msg = document.getElementById("msg") as HTMLElement;
  private history = document.getElementById("history") as HTMLElement;
  private hist: number[] = [];

  bind(onAction: () => void): void {
    this.action.addEventListener("click", onAction);
    document.querySelectorAll<HTMLElement>(".mini[data-act]").forEach((el) => {
      el.addEventListener("click", () => {
        const v = parseFloat(this.betInput.value) || 0;
        this.betInput.value = String(
          el.dataset.act === "half" ? Math.max(1, Math.floor(v / 2)) : Math.floor(v * 2) || 1,
        );
      });
    });
    window.addEventListener("keydown", (e) => {
      if (e.code === "Space" && e.target === document.body) {
        e.preventDefault();
        onAction();
      }
    });
  }

  getBet(): number {
    return Math.max(1, parseFloat(this.betInput.value) || 0);
  }

  /** Auto-sell multiplier, or undefined if the field is blank / invalid. */
  getAuto(): number | undefined {
    const v = parseFloat(this.autoInput.value);
    return Number.isFinite(v) && v > 1 ? v : undefined;
  }

  setBalance(v: number): void {
    this.bal.textContent = fmt(v);
  }

  setTicker(text: string): void {
    this.ticker.textContent = text;
  }

  setMsg(text: string): void {
    this.msg.textContent = text;
  }

  setMultiplier(m: number): void {
    this.mult.textContent = m.toFixed(2) + "×";
    this.mult.style.color = rgbToCss(multColor(m));
  }

  setMultiplierText(text: string, color: string): void {
    this.mult.textContent = text;
    this.mult.style.color = color;
  }

  setSellSub(text: string): void {
    const sub = this.action.querySelector(".sub");
    if (sub) sub.textContent = text;
  }

  setAction(mode: ActionMode, mult = 1): void {
    const b = this.action;
    if (mode === "buy") {
      b.className = "btn-buy";
      b.innerHTML = "Buy in &amp; launch 🚀";
      b.disabled = false;
    } else if (mode === "sell") {
      b.className = "btn-sell";
      b.innerHTML = `Sell now<span class="sub">lock ${mult.toFixed(2)}×</span>`;
      b.disabled = false;
    } else {
      b.className = "btn-wait";
      b.innerHTML = "next round…";
      b.disabled = true;
    }
  }

  pushHistory(crash: number): void {
    this.hist.unshift(crash);
    if (this.hist.length > 14) this.hist.pop();
    this.history.innerHTML = this.hist
      .map((c) => {
        const cl = c < 2 ? "lo" : c < 10 ? "mid" : "hi";
        return `<span class="chip ${cl}">${c.toFixed(2)}×</span>`;
      })
      .join("");
  }
}
