/**
 * SharedGame.ts — orchestrates the SHARED, server-driven round against the RGS.
 *
 * The server owns the round: it opens a betting window, broadcasts the curve tick
 * by tick, decides the crash, and reveals the seed. This client RENDERS that and
 * sends two intents only — place_bet (during the window) and cash_out. No outcome,
 * balance, or timing is ever computed here.
 *
 * Replaces the single-player Game.ts (where the player started their own round).
 */

import type { RgsClient } from "../net/RgsClient";
import { toCredits, toMinor } from "../net/protocol";
import type { CurveView } from "./CurveView";
import type { Hud } from "./Hud";
import type { Juice } from "./Juice";
import type { Feed } from "./Feed";
import type { MoonPool } from "./MoonPool";
import { multColor, rgbToCss, skyGradient, COLORS } from "./Theme";
import { rollTicker, launchLine } from "./flavor";
import { fmt } from "./format";

type Phase = "connecting" | "betting" | "inflight" | "crashed";

/** Cosmetic betting countdown length; mirrors the server's bettingMs (5s). */
const BETTING_SECONDS = 5;

interface MyBet {
  betId: string;
  stakeCredits: number;
}

export class SharedGame {
  private phase: Phase = "connecting";
  private myBet: MyBet | null = null;
  private pendingBet = false; // bet sent, awaiting accept
  private cashed = false;
  private lastMult = 1;
  private t0 = 0;
  private countdown = 0;
  private pendingJackpot: number | null = null;

  constructor(
    private rgs: RgsClient,
    private hud: Hud,
    private curve: CurveView,
    private juice: Juice,
    private feed: Feed,
    private moonPool: MoonPool,
    private stageEl: HTMLElement,
    private fairEl: HTMLElement,
  ) {}

  async boot(): Promise<void> {
    this.hud.bind(() => this.onAction());
    this.wire();
    const w = await this.rgs.connect();
    this.hud.setBalance(toCredits(w.balance));
    this.moonPool.set(toCredits(w.moonPool), false);
    this.hud.setTicker("connected · waiting for next round…");
    this.hud.setMsg("the next round opens shortly");
    this.hud.setAction("wait");
  }

  liveMult(): number {
    return this.lastMult;
  }

  // ---- intents ----
  private onAction(): void {
    if (this.phase === "betting" && !this.myBet && !this.pendingBet) {
      this.juice.ensureAudio();
      const credits = this.hud.getBet();
      this.pendingBet = true;
      this.hud.setAction("wait");
      this.hud.setMsg("placing bet…");
      this.rgs.placeBet(toMinor(credits), this.hud.getAuto());
    } else if (this.phase === "inflight" && this.myBet && !this.cashed) {
      this.rgs.cashOut(this.myBet.betId);
    }
  }

  // ---- server-driven render ----
  private wire(): void {
    this.rgs.on("round_open", (m) => {
      this.phase = "betting";
      this.myBet = null;
      this.pendingBet = false;
      this.cashed = false;
      this.lastMult = 1;
      this.clearCountdown();
      this.curve.clear();
      this.moonPool.set(toCredits(m.moonPool), false);
      this.fairEl.textContent = m.round.commitment.slice(0, 16) + "…";
      this.hud.setMultiplierText("1.00×", rgbToCss(multColor(1)));
      this.stageEl.style.background = skyGradient(1);
      this.hud.setMsg("buy in before it launches");
      this.hud.setAction("buy");
      this.startCountdown();
    });

    this.rgs.on("bet_accepted", (m) => {
      this.pendingBet = false;
      this.myBet = { betId: m.betId, stakeCredits: toCredits(m.stake) };
      this.hud.setBalance(toCredits(m.balance));
      this.hud.setMsg(`in for ${fmt(toCredits(m.stake))} · ride the pump`);
      if (this.phase === "betting") this.hud.setAction("wait");
    });

    this.rgs.on("betting_closed", () => {
      this.phase = "inflight";
      this.clearCountdown();
      this.t0 = performance.now();
      this.curve.reset();
      this.hud.setTicker(launchLine(rollTicker()));
      this.juice.startTone();
      this.feed.start();
      if (this.myBet && !this.cashed) this.hud.setAction("sell", 1);
      else {
        this.hud.setAction("wait");
        this.hud.setMsg("watching this round · bet on the next");
      }
    });

    this.rgs.on("tick", (m) => {
      if (this.phase !== "inflight") return;
      const mult = m.multiplier;
      this.lastMult = mult;
      const elapsed = (performance.now() - this.t0) / 1000;
      this.hud.setMultiplier(mult);
      this.curve.pushPoint(elapsed, mult);
      this.juice.setTone(mult);
      this.stageEl.style.background = skyGradient(mult);
      if (this.myBet && !this.cashed) {
        this.hud.setAction("sell", mult);
        this.hud.setSellSub(`lock ${mult.toFixed(2)}× = ${fmt(this.myBet.stakeCredits * mult)}`);
      }
    });

    this.rgs.on("cash_out", (m) => {
      this.cashed = true;
      this.hud.setBalance(toCredits(m.balance));
      const at = m.multiplier;
      const profit = toCredits(m.payout) - (this.myBet?.stakeCredits ?? 0);
      this.hud.setMultiplier(at);
      this.hud.setMsg(`sold @ ${at.toFixed(2)}× · +${fmt(profit)}`);
      this.hud.setAction("wait");
      this.juice.popMult();
      this.curve.burst(multColor(at));
      this.juice.bigWin(`+${fmt(profit)} 🤑`, "gold");
      this.juice.winSound();
    });

    this.rgs.on("cash_out_failed", (m) => {
      this.hud.setMsg(m.reason === "too_late" ? "too late — it rugged" : "cash-out failed");
    });

    this.rgs.on("jackpot", (m) => {
      this.pendingJackpot = toCredits(m.award);
      this.hud.setBalance(toCredits(m.balance));
    });

    this.rgs.on("balance", (m) => this.hud.setBalance(toCredits(m.balance)));

    this.rgs.on("crash", (m) => {
      this.phase = "crashed";
      this.juice.stopTone();
      this.feed.stop();
      const crash = m.round.crashPoint;
      this.fairEl.innerHTML = `seed <b>${m.round.serverSeed.slice(0, 16)}…</b> revealed`;

      if (this.myBet && !this.cashed) {
        this.hud.setMultiplierText("RUGGED", COLORS.rug);
        this.hud.setTicker("💀 dev dumped · liquidity gone");
        this.hud.setMsg(`rugged @ ${crash.toFixed(2)}× · −${fmt(this.myBet.stakeCredits)}`);
        this.stageEl.style.background = skyGradient(crash, true);
        this.curve.setRugged();
        this.juice.shake();
        this.juice.rugSound();
      } else {
        this.hud.setTicker(`rugged @ ${crash.toFixed(2)}×`);
        this.curve.setRugged();
      }

      // Moon Pool is independent of win/loss — celebrate a server-reported hit.
      if (this.pendingJackpot !== null) {
        const award = this.pendingJackpot;
        this.pendingJackpot = null;
        window.setTimeout(() => this.moonPool.celebrate(award, toCredits(m.moonPool)), 650);
      } else {
        this.moonPool.set(toCredits(m.moonPool), false);
      }
      this.hud.pushHistory(crash);
      this.hud.setAction("wait");
    });

    this.rgs.on("error", (m) => {
      if (m.code === "closed") {
        this.phase = "connecting";
        this.hud.setTicker("disconnected · reload to reconnect");
        this.hud.setMsg("lost connection to the game server");
        this.hud.setAction("wait");
      } else {
        this.hud.setMsg(m.message || "server error");
        this.pendingBet = false;
      }
    });
  }

  // ---- betting countdown (cosmetic; server `betting_closed` is authoritative) ----
  private startCountdown(): void {
    this.countdown = BETTING_SECONDS;
    const tick = () => {
      if (this.phase !== "betting") return;
      this.hud.setTicker(this.countdown > 0 ? `launching in ${this.countdown}s — buy in!` : "launching…");
      this.countdown -= 1;
    };
    tick();
    this.countdownTimer = window.setInterval(tick, 1000);
  }

  private countdownTimer = 0;
  private clearCountdown(): void {
    if (this.countdownTimer) window.clearInterval(this.countdownTimer);
    this.countdownTimer = 0;
  }
}
