/**
 * MoonPool.ts — Moon Pool display, climb animation, and moon-hit celebration.
 *
 * DISPLAY ONLY. The pool balance and the trigger are owned by the RGS and (in
 * production) shared across all players. This component renders the number it is
 * told and celebrates a hit the server reports — it never decides one.
 */

import type { CurveView } from "./CurveView";
import type { Juice } from "./Juice";
import { fmt } from "./format";

export class MoonPool {
  private el: HTMLElement;
  private msgEl: HTMLElement;
  private curve: CurveView;
  private juice: Juice;
  private value = 0;

  constructor(opts: { el: HTMLElement; msgEl: HTMLElement; curve: CurveView; juice: Juice }) {
    this.el = opts.el;
    this.msgEl = opts.msgEl;
    this.curve = opts.curve;
    this.juice = opts.juice;
  }

  /** Set the pool balance the server reported, with a small climb bump. */
  set(value: number, bump = true): void {
    this.value = value;
    this.el.textContent = fmt(value);
    if (bump) {
      this.el.classList.add("bump");
      setTimeout(() => this.el.classList.remove("bump"), 160);
    }
  }

  current(): number {
    return this.value;
  }

  /** Full celebration for a server-reported Moon Pool hit. */
  celebrate(award: number, poolAfter: number): void {
    this.juice.bigWin(`🌙 MOON POOL +${fmt(award)}`, "moon");
    this.curve.burst([255, 210, 63], false, 70); // gold
    this.curve.burst([255, 255, 255], false, 50); // white
    this.juice.moonSound();
    this.msgEl.textContent = `MOON POOL HIT · +${fmt(award)} credits`;
    this.set(poolAfter, true); // server already reset it to base
  }
}
