/**
 * CurveView.ts — the PixiJS (WebGL) pump curve, rocket, and particle system.
 *
 * Pure rendering. It plots whatever (time, multiplier) points the orchestrator
 * feeds it via pushPoint(); it does not know or compute the crash point. The
 * sky gradient lives on the stage element (CSS); Pixi renders transparently on
 * top so the neon glow + rocket composite over the shifting sky.
 *
 * Casino feel: twinkling starfield, a rocket that banks along the curve with a
 * flame trail, a multi-pass bloom on the line, and — on a crash — the rocket
 * nose-dives to the floor and detonates.
 */

import { Application, Container, Graphics, Text } from "pixi.js";
import { multColor, RUG_RGB, rgbToHex, type RGB } from "./Theme";

interface Pt {
  t: number;
  m: number;
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  decay: number;
  size: number;
  color: number;
  gravity: boolean;
}

interface Star {
  fx: number; // fraction of width
  fy: number; // fraction of height
  size: number;
  phase: number;
  speed: number;
  color: number;
}

const PAD_X = 16;
const PAD_BOTTOM = 22;
const PAD_TOP = 40;

export class CurveView {
  readonly app = new Application();
  private stars = new Graphics();
  private grid = new Graphics();
  private fill = new Graphics();
  private line = new Graphics();
  private fx = new Graphics();
  private rocket = new Text({ text: "🚀", style: { fontSize: 34 } });
  private starField: Star[] = [];
  private pts: Pt[] = [];
  private particles: Particle[] = [];
  private rugged = false;
  private currentMult = 1;
  private emitTrail = false;
  private lastRocket = { x: 0, y: 0 };

  async init(container: HTMLElement): Promise<void> {
    await this.app.init({
      resizeTo: container,
      backgroundAlpha: 0,
      antialias: true,
      resolution: window.devicePixelRatio || 1,
      autoDensity: true,
      preference: "webgl",
    });
    container.appendChild(this.app.canvas);

    this.rocket.anchor.set(0.5);
    this.rocket.visible = false;

    const root = new Container();
    root.addChild(this.stars, this.grid, this.fill, this.line, this.fx, this.rocket);
    this.app.stage.addChild(root);

    this.buildStars();
    this.app.ticker.add(() => this.render());
  }

  private buildStars(): void {
    const palette = [0xffffff, 0x22d3ee, 0xff2e97, 0xffd23f, 0x2bff88];
    this.starField = [];
    for (let i = 0; i < 60; i++) {
      // deterministic-ish scatter (no Math.random dependency for layout stability)
      const fx = ((i * 73) % 100) / 100;
      const fy = ((i * 37) % 100) / 100;
      this.starField.push({
        fx,
        fy,
        size: 0.6 + ((i * 17) % 10) / 6,
        phase: (i * 1.7) % (Math.PI * 2),
        speed: 0.001 + ((i % 5) * 0.0006),
        color: palette[i % palette.length],
      });
    }
  }

  /** Begin a fresh round: empty curve, trail emission on. */
  reset(): void {
    this.pts = [];
    this.rugged = false;
    this.currentMult = 1;
    this.emitTrail = true;
    this.rocket.visible = true;
  }

  /** Return to idle: empty curve, no trail, rocket parked. */
  clear(): void {
    this.pts = [];
    this.rugged = false;
    this.currentMult = 1;
    this.emitTrail = false;
    this.rocket.visible = false;
  }

  /** Feed the curve a sampled point. Color/scale follow from the multiplier. */
  pushPoint(t: number, m: number): void {
    this.currentMult = m;
    this.pts.push({ t, m });
    if (this.pts.length > 900) this.pts.shift();
  }

  /** The rocket crashed: nose-dive the line to the floor and detonate. */
  setRugged(): void {
    if (this.rugged) return;
    this.rugged = true;
    this.emitTrail = false;
    this.rocket.visible = false;
    // Snap the curve down to the floor for a visible plummet.
    const last = this.pts[this.pts.length - 1];
    if (last) {
      this.pts.push({ t: last.t + 0.08, m: 1 + (last.m - 1) * 0.4 });
      this.pts.push({ t: last.t + 0.16, m: 1 });
    }
    this.explode();
  }

  /** Celebratory burst of particles from the centre of the stage. */
  burst(color: RGB, gravity = false, count = 60): void {
    const W = this.app.screen.width;
    const H = this.app.screen.height;
    this.spawn(W / 2, H / 2, color, gravity, count, 14);
  }

  /** The crash detonation — debris from the rocket's last position, with gravity. */
  explode(): void {
    const { x, y } = this.lastRocket;
    this.spawn(x, y, RUG_RGB, true, 110, 18);
    this.spawn(x, y, [255, 200, 60], true, 40, 12); // orange sparks
  }

  private spawn(x: number, y: number, color: RGB, gravity: boolean, count: number, speed: number): void {
    for (let i = 0; i < count; i++) {
      const c: RGB = [
        Math.min(255, color[0] + (Math.random() * 50 - 20)),
        Math.min(255, color[1] + (Math.random() * 50 - 20)),
        Math.min(255, color[2] + (Math.random() * 50 - 20)),
      ];
      this.particles.push({
        x,
        y,
        vx: (Math.random() - 0.5) * speed,
        vy: (Math.random() - 0.5) * speed - (gravity ? 3 : 0),
        life: 1,
        decay: 0.01 + Math.random() * 0.01,
        size: Math.random() * 4 + 2,
        color: rgbToHex(c),
        gravity,
      });
    }
  }

  private curveColor(): RGB {
    return this.rugged ? RUG_RGB : multColor(this.currentMult);
  }

  private render(): void {
    const W = this.app.screen.width;
    const H = this.app.screen.height;
    this.drawStars(W, H);
    this.drawGrid(W, H);
    this.drawCurve(W, H);
    this.drawParticles();
  }

  private drawStars(W: number, H: number): void {
    const time = this.app.ticker.lastTime;
    this.stars.clear();
    for (const s of this.starField) {
      const tw = 0.35 + 0.4 * (0.5 + 0.5 * Math.sin(time * s.speed + s.phase));
      this.stars.circle(s.fx * W, s.fy * H, s.size).fill({ color: s.color, alpha: tw });
    }
  }

  private drawGrid(W: number, H: number): void {
    this.grid.clear();
    for (let i = 1; i < 5; i++) {
      const y = (H * i) / 5;
      this.grid.moveTo(0, y).lineTo(W, y);
    }
    this.grid.stroke({ width: 1, color: 0xffffff, alpha: 0.07 });
  }

  private drawCurve(W: number, H: number): void {
    this.fill.clear();
    this.line.clear();
    if (this.pts.length < 2) {
      this.rocket.visible = false;
      return;
    }

    const last = this.pts[this.pts.length - 1];
    const maxM = Math.max(2, this.currentMult * 1.1);
    const maxT = Math.max(3, last.t);
    const px = (p: Pt) => PAD_X + (p.t / maxT) * (W - PAD_X * 2);
    const py = (p: Pt) => H - PAD_BOTTOM - ((p.m - 1) / (maxM - 1)) * (H - PAD_BOTTOM - PAD_TOP);
    const rgb = this.curveColor();
    const color = rgbToHex(rgb);

    // translucent area fill under the curve
    this.fill.moveTo(px(this.pts[0]), H - PAD_BOTTOM);
    for (const p of this.pts) this.fill.lineTo(px(p), py(p));
    this.fill.lineTo(px(last), H - PAD_BOTTOM);
    this.fill.fill({ color, alpha: 0.3 });

    // bloom = three stacked strokes, wide+soft to crisp+bright
    const trace = (g: Graphics) => {
      g.moveTo(px(this.pts[0]), py(this.pts[0]));
      for (let i = 1; i < this.pts.length; i++) g.lineTo(px(this.pts[i]), py(this.pts[i]));
    };
    trace(this.line);
    this.line.stroke({ width: 18, color, alpha: 0.12, cap: "round", join: "round" });
    trace(this.line);
    this.line.stroke({ width: 9, color, alpha: 0.3, cap: "round", join: "round" });
    trace(this.line);
    this.line.stroke({ width: 4, color: 0xffffff, alpha: 0.95, cap: "round", join: "round" });
    trace(this.line);
    this.line.stroke({ width: 2, color, alpha: 1, cap: "round", join: "round" });

    // rocket rides the leading edge, banked along the curve tangent
    const lx = px(last);
    const ly = py(last);
    this.lastRocket = { x: lx, y: ly };
    if (!this.rugged) {
      const prev = this.pts[this.pts.length - 2];
      const ang = Math.atan2(ly - py(prev), lx - px(prev)); // screen-space travel angle
      this.rocket.visible = true;
      this.rocket.position.set(lx, ly);
      // 🚀 glyph points to the upper-right (~ -45°); align its nose to travel
      this.rocket.rotation = ang + Math.PI / 4;
      if (this.emitTrail && Math.random() < 0.9) {
        // flame trail behind the rocket
        this.spawnTrail(lx, ly, rgb);
      }
    }
  }

  private spawnTrail(x: number, y: number, color: RGB): void {
    this.particles.push({
      x: x - 6,
      y: y + 6,
      vx: (Math.random() - 0.5) * 1.4,
      vy: Math.random() * 1.8 + 0.6,
      life: 1,
      decay: 0.03,
      size: Math.random() * 3 + 2,
      color: rgbToHex(color),
      gravity: false,
    });
  }

  private drawParticles(): void {
    this.fx.clear();
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.x += p.vx;
      p.y += p.vy;
      if (p.gravity) p.vy += 0.35;
      p.life -= p.decay;
      if (p.life <= 0) {
        this.particles.splice(i, 1);
        continue;
      }
      this.fx.circle(p.x, p.y, p.size).fill({ color: p.color, alpha: Math.max(0, p.life) });
    }
  }
}
